#!/usr/bin/env bash

set -euo pipefail

# =============================================================================
# AWS Deployment Script
# Supports both local development and CI/CD environments
# =============================================================================

# Color codes for output
readonly RED='\033[0;31m'
readonly GREEN='\033[0;32m'
readonly YELLOW='\033[1;33m'
readonly BLUE='\033[0;34m'
readonly NC='\033[0m' # No Color

# Default configuration
readonly SCRIPT_NAME="$(basename "$0")"
readonly TIMESTAMP="$(date +%Y%m%d%H%M%S)"
readonly LOG_FILE="/tmp/aws-deploy-${TIMESTAMP}.log"

# Deployment defaults
DEFAULT_REGION="us-east-1"
DEFAULT_ENVIRONMENT="staging"
DEFAULT_S3_BUCKET=""
DEFAULT_STACK_NAME=""
DEFAULT_ECR_REPO=""
DEFAULT_ECS_CLUSTER=""
DEFAULT_ECS_SERVICE=""
DEFAULT_LAMBDA_FUNCTION=""
DEPLOY_TYPE=""
DRY_RUN=false
FORCE=false
ROLLBACK_ON_FAILURE=true

# =============================================================================
# Logging Functions
# =============================================================================

log() {
    local level="$1"
    shift
    local message="$*"
    local timestamp
    timestamp="$(date '+%Y-%m-%d %H:%M:%S')"
    echo -e "${timestamp} [${level}] ${message}" | tee -a "${LOG_FILE}"
}

info() {
    log "INFO" "${GREEN}$*${NC}"
}

warn() {
    log "WARN" "${YELLOW}$*${NC}"
}

error() {
    log "ERROR" "${RED}$*${NC}"
}

debug() {
    if [[ "${VERBOSE:-false}" == "true" ]]; then
        log "DEBUG" "${BLUE}$*${NC}"
    fi
}

# =============================================================================
# Usage and Help
# =============================================================================

usage() {
    cat <<EOF
Usage: ${SCRIPT_NAME} [OPTIONS]

AWS Deployment Script - Deploy applications to AWS services

OPTIONS:
    -t, --type TYPE           Deployment type: s3, cloudformation, ecs, lambda, eb (required)
    -e, --environment ENV     Target environment: dev, staging, production (default: ${DEFAULT_ENVIRONMENT})
    -r, --region REGION       AWS region (default: ${DEFAULT_REGION})
    -p, --profile PROFILE     AWS CLI profile name (for local development)
    -b, --bucket BUCKET       S3 bucket name (for s3 deployment)
    -s, --stack STACK         CloudFormation stack name
    -c, --cluster CLUSTER     ECS cluster name
    --service SERVICE         ECS service name
    --ecr-repo REPO           ECR repository name
    --lambda-function FUNC    Lambda function name
    --template FILE           CloudFormation template file
    --source-dir DIR          Source directory to deploy (default: ./dist)
    --docker-file FILE        Dockerfile path (default: ./Dockerfile)
    --dry-run                 Perform a dry run without making changes
    --force                   Skip confirmation prompts
    --no-rollback             Disable automatic rollback on failure
    -v, --verbose             Enable verbose output
    -h, --help                Show this help message

ENVIRONMENT VARIABLES:
    AWS_ACCESS_KEY_ID         AWS access key (CI/CD)
    AWS_SECRET_ACCESS_KEY     AWS secret key (CI/CD)
    AWS_SESSION_TOKEN         AWS session token (optional, for assumed roles)
    AWS_DEFAULT_REGION        Default AWS region
    AWS_PROFILE               AWS CLI profile name
    DEPLOY_ENVIRONMENT        Target environment
    CI                        Set to 'true' in CI/CD environments

EXAMPLES:
    # Deploy static site to S3
    ${SCRIPT_NAME} -t s3 -b my-website-bucket -e production --source-dir ./build

    # Deploy CloudFormation stack
    ${SCRIPT_NAME} -t cloudformation -s my-stack --template template.yaml -e staging

    # Deploy to ECS
    ${SCRIPT_NAME} -t ecs -c my-cluster --service my-service --ecr-repo my-app -e production

    # Deploy Lambda function
    ${SCRIPT_NAME} -t lambda --lambda-function my-function --source-dir ./dist

    # Dry run
    ${SCRIPT_NAME} -t s3 -b my-bucket --dry-run
EOF
    exit 0
}

# =============================================================================
# Utility Functions
# =============================================================================

is_ci_environment() {
    [[ "${CI:-false}" == "true" ]] || \
    [[ -n "${GITHUB_ACTIONS:-}" ]] || \
    [[ -n "${GITLAB_CI:-}" ]] || \
    [[ -n "${JENKINS_URL:-}" ]] || \
    [[ -n "${CIRCLECI:-}" ]] || \
    [[ -n "${TRAVIS:-}" ]] || \
    [[ -n "${CODEBUILD_BUILD_ID:-}" ]] || \
    [[ -n "${BITBUCKET_PIPELINE_UUID:-}" ]]
}

confirm_action() {
    local message="$1"
    if [[ "${FORCE}" == "true" ]] || is_ci_environment; then
        return 0
    fi
    echo -e "${YELLOW}${message}${NC}"
    read -rp "Continue? (y/N): " response
    [[ "${response}" =~ ^[Yy]$ ]]
}

cleanup() {
    local exit_code=$?
    if [[ ${exit_code} -ne 0 ]]; then
        error "Deployment failed with exit code ${exit_code}"
        error "Check log file: ${LOG_FILE}"
        if [[ "${ROLLBACK_ON_FAILURE}" == "true" && "${DRY_RUN}" == "false" ]]; then
            warn "Attempting rollback..."
            perform_rollback || error "Rollback failed!"
        fi
    fi
    # Clean up temporary files
    rm -f /tmp/aws-deploy-payload-*.zip 2>/dev/null || true
    exit ${exit_code}
}

trap cleanup EXIT

# =============================================================================
# AWS Authentication
# =============================================================================

check_aws_cli() {
    if ! command -v aws &>/dev/null; then
        error "AWS CLI is not installed. Please install it first."
        error "Visit: https://docs.aws.amazon.com/cli/latest/userguide/getting-started-install.html"
        exit 1
    fi
    local aws_version
    aws_version="$(aws --version 2>&1)"
    info "AWS CLI version: ${aws_version}"
}

configure_aws_auth() {
    info "Configuring AWS authentication..."

    # Set region
    export AWS_DEFAULT_REGION="${AWS_REGION:-${DEFAULT_REGION}}"
    info "Using AWS region: ${AWS_DEFAULT_REGION}"

    if is_ci_environment; then
        info "CI/CD environment detected"
        configure_ci_auth
    else
        info "Local development environment detected"
        configure_local_auth
    fi

    # Verify authentication
    verify_aws_auth
}

configure_ci_auth() {
    # In CI/CD, credentials should be provided via environment variables
    # or IAM roles (e.g., EC2 instance profile, ECS task role, GitHub OIDC)

    if [[ -n "${AWS_ROLE_ARN:-}" ]]; then
        info "Assuming IAM role: ${AWS_ROLE_ARN}"
        assume_role "${AWS_ROLE_ARN}"
    elif [[ -n "${AWS_ACCESS_KEY_ID:-}" && -n "${AWS_SECRET_ACCESS_KEY:-}" ]]; then
        info "Using AWS access key credentials from environment"
        # Credentials are already in environment variables
    elif [[ -n "${AWS_WEB_IDENTITY_TOKEN_FILE:-}" ]]; then
        info "Using Web Identity Token (OIDC) authentication"
        # AWS SDK handles this automatically
    else
        # Check for instance profile / task role
        info "Attempting to use instance profile or task role credentials"
    fi
}

configure_local_auth() {
    if [[ -n "${AWS_PROFILE:-}" ]]; then
        info "Using AWS profile: ${AWS_PROFILE}"
        export AWS_PROFILE
    elif [[ -n "${PROFILE:-}" ]]; then
        info "Using AWS profile: ${PROFILE}"
        export AWS_PROFILE="${PROFILE}"
    fi

    # Check for MFA requirement
    if [[ -n "${AWS_MFA_SERIAL:-}" ]]; then
        info "MFA is configured. Requesting MFA token..."
        request_mfa_token
    fi

    # Check for SSO
    if aws configure get sso_start_url --profile "${AWS_PROFILE:-default}" &>/dev/null 2>&1; then
        info "SSO profile detected. Ensuring SSO session is active..."
        aws sso login --profile "${AWS_PROFILE:-default}" 2>/dev/null || true
    fi
}

assume_role() {
    local role_arn="$1"
    local session_name="${AWS_ROLE_SESSION_NAME:-deploy-session-${TIMESTAMP}}"
    local duration="${AWS_ROLE_DURATION:-3600}"

    local assume_role_args=(
        sts assume-role
        --role-arn "${role_arn}"
        --role-session-name "${session_name}"
        --duration-seconds "${duration}"
        --output json
    )

    if [[ -n "${AWS_EXTERNAL_ID:-}" ]]; then
        assume_role_args+=(--external-id "${AWS_EXTERNAL_ID}")
    fi

    local credentials
    credentials="$(aws "${assume_role_args[@]}")"

    export AWS_ACCESS_KEY_ID
    export AWS_SECRET_ACCESS_KEY
    export AWS_SESSION_TOKEN
    AWS_ACCESS_KEY_ID="$(echo "${credentials}" | jq -r '.Credentials.AccessKeyId')"
    AWS_SECRET_ACCESS_KEY="$(echo "${credentials}" | jq -r '.Credentials.SecretAccessKey')"
    AWS_SESSION_TOKEN="$(echo "${credentials}" | jq -r '.Credentials.SessionToken')"

    info "Successfully assumed role: ${role_arn}"
}

request_mfa_token() {
    local mfa_serial="${AWS_MFA_SERIAL}"
    local token_code

    read -rp "Enter MFA token code: " token_code

    local credentials
    credentials="$(aws sts get-session-token \
        --serial-number "${mfa_serial}" \
        --token-code "${token_code}" \
        --output json)"

    export AWS_ACCESS_KEY_ID
    export AWS_SECRET_ACCESS_KEY
    export AWS_SESSION_TOKEN
    AWS_ACCESS_KEY_ID="$(echo "${credentials}" | jq -r '.Credentials.AccessKeyId')"
    AWS_SECRET_ACCESS_KEY="$(echo "${credentials}" | jq -r '.Credentials.SecretAccessKey')"
    AWS_SESSION_TOKEN="$(echo "${credentials}" | jq -r '.Credentials.SessionToken')"

    info "MFA authentication successful"
}

verify_aws_auth() {
    info "Verifying AWS credentials..."
    local identity
    if ! identity="$(aws sts get-caller-identity --output json 2>&1)"; then
        error "AWS authentication failed: ${identity}"
        error "Please check your credentials and try again."
        exit 1
    fi

    local account_id arn
    account_id="$(echo "${identity}" | jq -r '.Account')"
    arn="$(echo "${identity}" | jq -r '.Arn')"

    info "Authenticated as: ${arn}"
    info "AWS Account: ${account_id}"

    # Safety check: warn if deploying to production
    if [[ "${ENVIRONMENT}" == "production" ]]; then
        warn "⚠️  WARNING: You are deploying to PRODUCTION in account ${account_id}"
        if ! confirm_action "Are you sure you want to deploy to production?"; then
            error "Deployment cancelled by user"
            exit 1
        fi
    fi
}

# =============================================================================
# S3 Deployment
# =============================================================================

deploy_s3() {
    local bucket="${S3_BUCKET}"
    local source_dir="${SOURCE_DIR:-./dist}"

    if [[ -z "${bucket}" ]]; then
        error "S3 bucket name is required. Use -b or --bucket flag."
        exit 1
    fi

    if [[ ! -d "${source_dir}" ]]; then
        error "Source directory '${source_dir}' does not exist."
        exit 1
    fi

    info "Deploying to S3 bucket: ${bucket}"
    info "Source directory: ${source_dir}"

    # Check if bucket exists
    if ! aws s3api head-bucket --bucket "${bucket}" 2>/dev/null; then
        error "S3 bucket '${bucket}' does not exist or you don't have access."
        exit 1
    fi

    local sync_args=(
        s3 sync "${source_dir}" "s3://${bucket}"
        --delete
        --no-progress
    )

    # Add cache control headers for common file types
    if [[ "${DRY_RUN}" == "true" ]]; then
        sync_args+=(--dryrun)
        info "[DRY RUN] Would sync files to s3://${bucket}"
    fi

    info "Syncing files..."
    aws "${sync_args[@]}" 2>&1 | tee -a "${LOG_FILE}"

    # Set cache headers for different file types
    if [[ "${DRY_RUN}" == "false" ]]; then
        info "Setting cache control headers..."

        # Long cache for hashed assets
        aws s3 cp "s3://${bucket}" "s3://${bucket}" \
            --recursive \
            --exclude "*" \
            --include "*.js" \
            --include "*.css" \
            --include "*.woff2" \
            --include "*.woff" \
            --include "*.ttf" \
            --metadata-directive REPLACE \
            --cache-control "public, max-age=31536000, immutable" \
            --no-progress 2>&1 | tee -a "${LOG_FILE}" || true

        # Short cache for HTML
        aws s3 cp "s3://${bucket}" "s3://${bucket}" \
            --recursive \
            --exclude "*" \
            --include "*.html" \
            --metadata-directive REPLACE \
            --cache-control "public, max-age=300" \
            --content-type "text/html" \
            --no-progress 2>&1 | tee -a "${LOG_FILE}" || true

        # Invalidate CloudFront if distribution ID is set
        if [[ -n "${CLOUDFRONT_DISTRIBUTION_ID:-}" ]]; then
            info "Invalidating CloudFront distribution: ${CLOUDFRONT_DISTRIBUTION_ID}"
            aws cloudfront create-invalidation \
                --distribution-id "${CLOUDFRONT_DISTRIBUTION_ID}" \
                --paths "/*" 2>&1 | tee -a "${LOG_FILE}"
        fi
    fi

    info "S3 deployment completed successfully!"
}

# =============================================================================
# CloudFormation Deployment
