deploy_cloudformation() {
    local stack_name="${STACK_NAME}"
    local template_file="${TEMPLATE_FILE:-template.yaml}"

    if [[ -z "${stack_name}" ]]; then
        error "CloudFormation stack name is required. Use -s or --stack flag."
        exit 1
    fi

    if [[ ! -f "${template_file}" ]]; then
        error "CloudFormation template '${template_file}' not found."
        exit 1
    fi

    info "Deploying CloudFormation stack: ${stack_name}"
    info "Template: ${template_file}"

    # Validate template
    info "Validating CloudFormation template..."
    if ! aws cloudformation validate-template --template-body "file://${template_file}" 2>&1 | tee -a "${LOG_FILE}"; then
        error "Template validation failed."
        exit 1
    fi

    if [[ "${DRY_RUN}" == "true" ]]; then
        info "[DRY RUN] Creating change set for review..."
        local changeset_name="dry-run